#include<stdio.h>

int main(void){
	int n;
	char k;
	scanf("%c%d", &k,&n);
	if((k=='a'||k=='h')&&(n==8 || n==1)){
		printf("3");
		return 0;
	}
	if(n==1 || n==8 || k=='a' || k=='h'){
		printf("5");
		return 0;
	}
	printf("8");
	return 0;
}

